}

#[test]
fn test_byte_comma_separated_with_spaces() {
    let mut asm = Assembler::new();
    // Spaces after commas (as24 style)
    let result = asm.assemble(".byte 72, 101, 108, 108, 111");
    assert!(result.errors.is_empty(), "Errors: {:?}", result.errors);
