1	use std::ffi::OsString;
2	use std::fs;
3	use std::io::{self, IsTerminal, Read, Write};
4	use std::path::{Path, PathBuf};
5	use std::process::ExitCode;
6	
7	use cor24_assembler::{Assembler, AssemblyResult, lgo, listing};
8	
9	const PKG_VERSION: &str = env!("CARGO_PKG_VERSION");
10	
11	const USAGE: &str = "\
12	cor24-asm — COR24 cross-assembler
13	
14	USAGE:
15	    cor24-asm <input.s>                                  Assemble; write <stem>.lgo next to input
16	    cor24-asm <input.s> -o <out.lgo>                     Explicit .lgo output path
17	    cor24-asm <input.s> --bin <out.bin>                  Raw machine-code bytes (no .lgo)
18	    cor24-asm <input.s> --bin <bin> --listing <lst>      Bytes + listing
19	    cor24-asm <input.s> -o <lgo> --bin <bin> --listing <lst>
20	                                                         All three artifacts
21	    cor24-asm -                                          Read .s from stdin, write .lgo to stdout
22	    cor24-asm -V | --version                             Print version
23	    cor24-asm -h | --help                                Print this help
24	
25	OPTIONS:
26	    --base-addr <addr>    Assemble at a non-zero base address. Labels resolve
27	                          to base + offset; .lgo L-records and .lst addresses
28	                          shift accordingly. Output bytes still start at offset
29	                          0 (no leading padding). Accepts 0x-prefixed hex,
30	                          h-suffixed hex, or decimal. Default: 0.
31	
32	EXIT CODES:
33	    0    clean assembly
34	    1    assembly errors (one per line on stderr)
35	    2    usage / IO errors
36	
37	When writing .lgo or .bin to stdout, the destination must not be a terminal.
38	Redirect to a file or use an explicit path.";
39	
40	fn main() -> ExitCode {
41	    let args: Vec<OsString> = std::env::args_os().skip(1).collect();
42	    match run(args) {
43	        Ok(code) => code,
44	        Err(e) => {
45	            eprintln!("cor24-asm: {}", e);
46	            ExitCode::from(2)
47	        }
48	    }
49	}
50	
51	#[derive(Debug)]
52	enum InputSource {
53	    File(PathBuf),
54	    Stdin,
55	}
56	
57	impl InputSource {
58	    fn label(&self) -> String {
59	        match self {
60	            InputSource::File(p) => p.display().to_string(),
61	            InputSource::Stdin => "<stdin>".to_string(),
62	        }
63	    }
64	}
65	
66	#[derive(Debug, Default)]
67	enum LgoSink {
68	    /// Write to <input-stem>.lgo when input is a file.
69	    #[default]
70	    AutoFromStem,
71	    /// Explicit -o path. `-` means stdout.
72	    Explicit(PathBuf),
73	    /// No .lgo output requested.
74	    None,
75	}
76	
77	#[derive(Debug, Default)]
78	struct Cli {
79	    input: Option<InputSource>,
80	    lgo: LgoSink,
81	    bin: Option<PathBuf>,
82	    listing: Option<PathBuf>,
83	    base_addr: u32,
84	}
85	
86	fn run(args: Vec<OsString>) -> Result<ExitCode, String> {
87	    let mut cli = Cli::default();
88	    let mut iter = args.into_iter();
89	
90	    while let Some(arg) = iter.next() {
91	        let s = arg.to_string_lossy();
92	        match s.as_ref() {
93	            "-h" | "--help" => {
94	                println!("{}", USAGE);
95	                return Ok(ExitCode::SUCCESS);
96	            }
97	            "-V" | "--version" => {
98	                println!("cor24-asm {}", PKG_VERSION);
99	                return Ok(ExitCode::SUCCESS);
100	            }
101	            "-o" => {
102	                let v = iter
103	                    .next()
104	                    .ok_or_else(|| "-o requires an argument".to_string())?;
105	                cli.lgo = LgoSink::Explicit(PathBuf::from(v));
106	            }
107	            "--bin" => {
108	                let v = iter
109	                    .next()
110	                    .ok_or_else(|| "--bin requires an argument".to_string())?;
111	                cli.bin = Some(PathBuf::from(v));
112	            }
113	            "--listing" => {
114	                let v = iter
115	                    .next()
116	                    .ok_or_else(|| "--listing requires an argument".to_string())?;
117	                cli.listing = Some(PathBuf::from(v));
118	            }
119	            "--base-addr" => {
120	                let v = iter
121	                    .next()
122	                    .ok_or_else(|| "--base-addr requires an argument".to_string())?;
123	                let s = v.to_string_lossy();
124	                cli.base_addr = parse_numeric_addr(&s).ok_or_else(|| {
125	                    format!(
126	                        "invalid --base-addr value '{}': expected hex (0x.../...h) or decimal",
127	                        s
128	                    )
129	                })?;
130	            }
131	            "-" => {
132	                if cli.input.is_some() {
133	                    return Err("multiple inputs not supported".to_string());
134	                }
135	                cli.input = Some(InputSource::Stdin);
136	            }
137	            other if other.starts_with("--") || (other.starts_with('-') && other.len() > 1) => {
138	                return Err(format!("unknown option '{}'", other));
139	            }
140	            _ => {
141	                if cli.input.is_some() {
142	                    return Err("multiple inputs not supported".to_string());
143	                }
144	                cli.input = Some(InputSource::File(PathBuf::from(arg)));
145	            }
146	        }
147	    }
148	
149	    let input = cli
150	        .input
151	        .take()
152	        .ok_or_else(|| "no input file (use '-' for stdin); see --help".to_string())?;
153	
154	    // If --bin is supplied without -o, suppress the default <stem>.lgo write.
155	    if cli.bin.is_some() && matches!(cli.lgo, LgoSink::AutoFromStem) {
156	        cli.lgo = LgoSink::None;
157	    }
158	
159	    let source = read_input(&input).map_err(|e| format!("{}: {}", input.label(), e))?;
160	
161	    let mut asm = Assembler::new();
162	    let result = asm.assemble_at(&source, cli.base_addr);
163	
164	    if !result.errors.is_empty() {
165	        let label = input.label();
166	        for err in &result.errors {
167	            eprintln!("{}: {}", label, err);
168	        }
169	        return Ok(ExitCode::from(1));
170	    }
171	
172	    write_outputs(&input, &cli, &result)?;
173	    Ok(ExitCode::SUCCESS)
174	}
175	
176	fn read_input(src: &InputSource) -> io::Result<String> {
177	    match src {
178	        InputSource::File(p) => fs::read_to_string(p),
179	        InputSource::Stdin => {
180	            let mut buf = String::new();
181	            io::stdin().read_to_string(&mut buf)?;
182	            Ok(buf)
183	        }
184	    }
185	}
186	
187	fn write_outputs(input: &InputSource, cli: &Cli, result: &AssemblyResult) -> Result<(), String> {
188	    match &cli.lgo {
189	        LgoSink::AutoFromStem => {
190	            let path = match input {
191	                InputSource::File(p) => default_lgo_path(p),
192	                InputSource::Stdin => {
193	                    // stdin with no -o: write .lgo to stdout (refuse TTY).
194	                    return write_lgo_to_stdout(result, cli.base_addr)
195	                        .and_then(|_| write_optional_extras(cli, result));
196	                }
197	            };
198	            write_lgo_to_path(&path, result, cli.base_addr)?;
199	        }
200	        LgoSink::Explicit(p) => {
201	            if p == Path::new("-") {
202	                write_lgo_to_stdout(result, cli.base_addr)?;
203	            } else {
204	                write_lgo_to_path(p, result, cli.base_addr)?;
205	            }
206	        }
207	        LgoSink::None => {}
208	    }
209	    write_optional_extras(cli, result)
210	}
211	
212	fn write_optional_extras(cli: &Cli, result: &AssemblyResult) -> Result<(), String> {
213	    if let Some(p) = &cli.bin {
214	        if p == Path::new("-") {
215	            refuse_tty("cannot write .bin to a terminal")?;
216	            io::stdout()
217	                .write_all(&result.bytes)
218	                .map_err(|e| format!("writing .bin to stdout: {}", e))?;
219	        } else {
220	            fs::write(p, &result.bytes)
221	                .map_err(|e| format!("writing {}: {}", p.display(), e))?;
222	        }
223	    }
224	    if let Some(p) = &cli.listing {
225	        if p == Path::new("-") {
226	            listing::write(result, &mut io::stdout())
227	                .map_err(|e| format!("writing listing to stdout: {}", e))?;
228	        } else {
229	            let mut f = fs::File::create(p)
230	                .map_err(|e| format!("creating {}: {}", p.display(), e))?;
231	            listing::write(result, &mut f)
232	                .map_err(|e| format!("writing {}: {}", p.display(), e))?;
233	        }
234	    }
235	    Ok(())
236	}
237	
238	fn default_lgo_path(input: &Path) -> PathBuf {
239	    let mut p = input.to_path_buf();
240	    p.set_extension("lgo");
241	    p
242	}
243	
244	fn write_lgo_to_path(path: &Path, result: &AssemblyResult, base_addr: u32) -> Result<(), String> {
245	    let mut f =
246	        fs::File::create(path).map_err(|e| format!("creating {}: {}", path.display(), e))?;
247	    lgo::write(&result.bytes, base_addr, None, &mut f)
248	        .map_err(|e| format!("writing {}: {}", path.display(), e))
249	}
250	
251	fn write_lgo_to_stdout(result: &AssemblyResult, base_addr: u32) -> Result<(), String> {
252	    refuse_tty("cannot write .lgo to a terminal")?;
253	    let mut out = io::stdout().lock();
254	    lgo::write(&result.bytes, base_addr, None, &mut out)
255	        .map_err(|e| format!("writing .lgo to stdout: {}", e))
256	}
257	
258	/// Parse a numeric address. Accepts:
259	/// - `0x`/`0X` prefix → hex
260	/// - trailing `h`/`H` suffix → hex
261	/// - otherwise → decimal
262	fn parse_numeric_addr(s: &str) -> Option<u32> {
263	    let s = s.trim();
