85	/// Load an LGO file, set PC, run for max_cycles
86	fn load_and_run(lgo_path: &str, entry: u32, max_cycles: u64) -> CpuState {
87	    let content = std::fs::read_to_string(lgo_path)
88	        .unwrap_or_else(|e| panic!("Cannot read {}: {}", lgo_path, e));
89	    let mut cpu = CpuState::new();
90	    cpu.io.uart_tx_busy_cycles = 0; // legacy: instant TX for .lgo programs that don't poll
91	    load_lgo(&content, &mut cpu).unwrap();
92	    cpu.pc = entry;
93	    let executor = Executor::new();
94	    executor.run(&mut cpu, max_cycles);
95	    cpu
96	}
