231	    let mut cpu = CpuState::new();
232	    cpu.io.uart_tx_busy_cycles = 0; // legacy: instant TX for tests that don't poll
233	    for (addr, byte) in result.bytes.iter().enumerate() {
234	        cpu.memory[addr] = *byte;
235	    }
236	    cpu.pc = 0;
237	    let executor = Executor::new();
238	    executor.run(&mut cpu, max_cycles);
239	    cpu
240	}
